// Compute yesterday in PHT (UTC+8) as YYYY-MM-DD
const now    = new Date();
const phtMs  = now.getTime() + (8 * 60 * 60 * 1000);
const phtNow = new Date(phtMs);
phtNow.setDate(phtNow.getDate() - 1);
const yyyy = phtNow.getUTCFullYear();
const mm   = String(phtNow.getUTCMonth() + 1).padStart(2, '0');
const dd   = String(phtNow.getUTCDate()).padStart(2, '0');
const reconciliationDate = `${yyyy}-${mm}-${dd}`;
return [{ json: { reconciliation_date: reconciliationDate } }];

// Both branches have completed. Read results by node name (available in execution context).
const imisRow   = $node['Query IMIS totals'].first().json;
const casRes    = $node['GET CAS2000 daily totals'].first().json;
const reconDate = $node['Compute yesterday PHT'].first().json.reconciliation_date;

const imisTotal    = parseFloat(imisRow.imis_total ?? '0');
const casAvailable = casRes.statusCode <= 299;
const casTotal     = casAvailable
  ? parseFloat(casRes.body?.total_debits ?? '0')
  : 0;

const variance  = parseFloat((imisTotal - casTotal).toFixed(4));
const isMatched = Math.abs(variance) < 0.01;
const status    = !casAvailable ? 'pending' : (isMatched ? 'matched' : 'variance');

const casTransactions = casRes.body?.transactions ?? [];
const details = {
  imis_transaction_count: imisRow.transaction_count,
  cas_available:          casAvailable,
  cas_transactions:       casTransactions,
  variance_explanation:   isMatched
    ? 'Totals match within tolerance (< 0.01 PHP)'
    : `Variance of ${Math.abs(variance).toFixed(4)} PHP detected`,
};

return [{ json: {
  reconciliation_date: reconDate,
  imis_total:          imisTotal,
  cas_total_debits:    casTotal,
  variance,
  matched_count:       isMatched ? imisRow.transaction_count : 0,
  unmatched_count:     isMatched ? 0 : imisRow.transaction_count,
  status,
  details:             JSON.stringify(details),
  has_variance:        !isMatched && casAvailable,
} }];

